<?php
namespace App\Jobs;
use App\Enums\PrintOrderStatus; use App\Models\PrintOrder; use App\Services\Esp32DeviceService; use App\Services\LockerAssignmentService; use App\Services\OrderStatusService; use Illuminate\Contracts\Queue\ShouldQueue; use Illuminate\Foundation\Queue\Queueable; use Illuminate\Support\Facades\DB;
class DiscardExpiredOrderJob implements ShouldQueue { use Queueable; public function __construct(public int $orderId){} public function handle(Esp32DeviceService $device,OrderStatusService $statuses,LockerAssignmentService $lockers):void{DB::transaction(function()use($device,$statuses,$lockers){$order=PrintOrder::lockForUpdate()->findOrFail($this->orderId);if($order->status!==PrintOrderStatus::ReadyForPickup||$order->expires_at->isFuture())return;$statuses->transition($order,PrintOrderStatus::Expired,'Pickup deadline passed.');$statuses->transition($order,PrintOrderStatus::DroppingToTrash,'Moving document to the discard tray.');$device->openTrashDoor($order);sleep(max(0,(int)config('queueless.trash_open_seconds')));$device->closeTrashDoor($order);$statuses->transition($order,PrintOrderStatus::Discarded,'Document discarded.',['discarded_at'=>now()]);$lockers->release($order);$device->setLockerAvailable($order);});} }
